  (341, 'Built castles in the air', 'Creating unrealistic daydreams or plans.', 'ख़याली पुलाव पकाना', 'idiom'),
  (342, 'Built on credit', 'Operating on borrowed financial terms.', 'उधारी पर आधारित', 'phrase'),
  (343, 'Pulled strings', 'To use secret personal influence, connections, or clout to achieve a desired outcome.', 'व्यक्तिगत प्रभाव का प्रयोग करना', 'idiom'),
  (344, 'Closed the book', 'Stopped working on a project or topic.', 'कार्य बंद करना', 'idiom'),
  (345, 'Sought after', 'Highly in demand because of its exceptional quality.', 'लोकप्रिय', 'idiom'),
  (346, 'To hit below the belt', 'To attack someone unfairly, dishonestly, or breach the rules of fair play.', 'बेईमानी करना', 'idiom'),
  (347, 'To run in the same groove', 'To advance or operate in perfect harmony.', 'सद्भाव में अग्रसर', 'idiom'),
  (348, 'To keep your head', 'To remain calm and composed in a crisis.', 'अपनी सुध बुध बनाये रखना', 'idiom'),
  (349, 'Building castles in the air', 'Making highly impractical plans, daydreams, or visionary schemes that have no real basis.', 'ख़याली पुलाव पकाना', 'idiom'),
  (350, 'Running in the same groove', 'Progressing steadily in perfect harmony.', 'सद्भाव में अग्रसर', 'idiom'),
  (351, 'Keeping his head', 'Remaining calm and collected under pressure.', 'अपनी सुध बुध बनाये रखना', 'idiom'),
  (352, 'To explore every avenue', 'To try every opportunity.', 'हर संभव तरीका जांचना', 'idiom'),
  (353, 'At one''s beck and call', 'Ready to follow orders.', 'इशारे पर नाचने वाला', 'idiom'),
  (354, 'Status quo', 'As it is or unchanged position.', 'यथास्थिति', 'idiom'),
  (355, 'By fair or foul means', 'In an honest or dishonest way.', 'किसी भी तरह', 'idiom'),
  (356, 'To hit the jackpot', 'To make money quickly or get sudden success.', 'किस्मत का तारा चमक उठना', 'idiom'),
  (357, 'To bring to light', 'To reveal or make visible.', 'प्रकाशित करना', 'idiom'),
  (358, 'To shed crocodile tears', 'To pretend grief.', 'घड़ियाली आंसू बहाना', 'idiom'),
  (359, 'To look down one''s nose', 'To regard with contempt.', 'तिरस्कार करना', 'idiom'),
  (360, 'To miss the bus', 'To miss an opportunity.', 'मौका गँवा बैठना', 'idiom'),
  (361, 'To call spade a spade', 'To be frank and direct.', 'स्पष्ट बोलना', 'idiom'),
  (362, 'Birds of same feather', 'Persons of the same character.', 'एक ही थैली के चट्टे-बट्टे', 'idiom'),
  (363, 'Fall short', 'Fail to meet expectations.', 'अपर्याप्त होना', 'idiom'),
  (364, 'Heart to heart talk', 'A frank, intimate conversation.', 'स्वच्छंद एवं आंतरिक बातचीत', 'idiom'),
  (365, 'Give the game away', 'Reveal a secret accidentally.', 'गलती से राज़ उजागर करना', 'idiom'),
  (366, 'Take cue from', 'To copy past successful actions.', 'दृढ़ता से प्रभावित होना', 'idiom'),
  (367, 'Call for', 'To demand or request.', 'मांगना', 'idiom'),
  (368, 'End up in smoke', 'Come to nothing.', 'कोई परिणाम न निकलना', 'idiom'),
  (369, 'Spread like fire', 'Disseminate rapidly.', 'जंगल की आग की तरह फैलना', 'idiom'),
  (370, 'Dropping like flies', 'Collapsing in large numbers.', 'बड़ी संख्या में मरना', 'idiom'),
  (371, 'Rat race', 'Fierce competition for power.', 'तीव्र प्रतियोगिता', 'idiom'),
  (372, 'See eye to eye', 'Agree completely with someone.', 'पूरी तरह से सहमत होना', 'idiom'),
  (373, 'To have second thoughts', 'To reconsider a decision or choice.', 'सोच-ववचार िााेांपड़ जाना', 'idiom')
INSERT INTO public.idiom_questions (id, question, option_a, option_b, option_c, option_d, answer, idiom_id)
VALUES
  (1, 'Instead of analyzing the data carefully, the manager made a ___________ about the drop in sales, blaming it entirely on the new team members without any proof.', 'sweeping statement', 'green thumb', 'white elephant', 'close shave', 'a', 1),
  (2, '"To be completely puzzled, confused, or lost in a difficult situation."', 'Going places', 'In a tight corner', 'All at sea', 'Out and out', 'c', 5),
  (3, 'The software development company decided to give its creative designers ___________ to experiment with the new app interface without strict supervision.', 'no love lost between', 'enough rope', 'hard and fast', 'on the cuff', 'b', 9),
  (4, '"Working or progressing irregularly with frequent stops, starts, and interruptions."', 'Off and on', 'By fits and starts', 'Face the music', 'Look down upon', 'b', 13),
  (5, 'The young accounts officer ___________ the tax department when he accidentally submitted altered balance sheets.', 'fell foul of', 'played havoc', 'took to heels', 'made a clean breast', 'a', 17),
  (6, '"A brief, short-duration strike held by workers as a warning to the management before launching a larger protest."', 'Token strike', 'Wild goose chase', 'In cold blood', 'Does not hold water', 'a', 21),
  (7, 'After leaking the confidential product designs to a rival firm, the senior developer was called into the boardroom to ___________.', 'keep up', 'fair and square', 'face the music', 'flog a dead horse', 'c', 15),
  (8, '"To regard or treat someone with intense hatred, contempt, or a feeling of superiority."', 'Look down upon', 'Under a cloud', 'Rest on laurels', 'Heads will roll', 'a', 16),
  (9, 'Trying to convince the old landlord to upgrade the building''s wiring is like ___________; he simply refuses to spend a single penny.', 'making no bones about', 'flogging a dead horse', 'paying through nose', 'drawing on fancy', 'b', 31),
  (10, '"Being under severe suspicion, distrust, or official investigation regarding a wrongdoing."', 'Under a cloud', 'In a tight corner', 'Off and on', 'Out and out', 'a', 28),
  (11, 'The flash floods ___________ across the coastal villages, washing away houses, roads, and electric grids overnight.', 'staved off', 'played havoc', 'took after', 'turned an honest living', 'b', 18),
  (12, '"The state of having bitter feelings, intense dislike, or bad terms between two parties."', 'No love lost between', 'Green thumb', 'Fair and square', 'White elephant', 'a', 10),
  (13, 'Everyone respects the new judge because his rulings are always ___________ and free from any personal bias.', 'out and out', 'on the cuff', 'fair and square', 'under a cloud', 'c', 26),
  (14, '"A possession that is highly expensive to maintain but serves absolutely no useful purpose to its owner."', 'Wild goose chase', 'White elephant', 'Hard and fast', 'Going places', 'b', 3),
  (15, 'The statement issued by the corrupt politician was an ___________ lie, and the media quickly exposed the contradictions.', 'out and out', 'all at sea', 'off and on', 'on the cuff', 'a', 8),
  (16, '"Buying items on credit or deferred payment, rather than paying with cash immediately."', 'By fits and starts', 'On the cuff', 'Does not hold water', 'Sweeping statement', 'b', 12),
  (17, 'Your excuse for arriving late to the crucial board meeting simply ___________; the train logs show no delays occurred this morning.', 'does not hold water', 'fells foul of', 'takes after', 'staves off', 'a', 24),
  (18, '"A hopeless, foolish, or entirely futile search for something that cannot be found or achieved."', 'Wild goose chase', 'Token strike', 'Flogging a dead horse', 'In a tight corner', 'a', 22),
  (19, 'After the sudden withdrawal of financial backing from the primary investors, the construction firm found itself ___________.', 'in a tight corner', 'going places', 'making no bones about', 'drawing on fancy', 'a', 7),
  (20, '"To possess a natural skill, passion, or innate interest in nurturing plants and handling gardening effectively."', 'Green thumb', 'Fair and square', 'Enough rope', 'Look down upon', 'a', 2),
  (21, 'With her brilliant tech innovations and extraordinary leadership skills, the young entrepreneur is clearly ___________.', 'under a cloud', 'going places', 'taking to heels', 'making a clean breast', 'b', 6),
  (22, '"A brutal crime or murder committed deliberately, with zero emotion, premeditated intention, and planning."', 'In cold blood', 'Played havoc', 'Hard and fast', 'Off and on', 'a', 23),
  (23, 'It has been raining ___________ for the past three weeks, making it almost impossible for the construction workers to pour the concrete foundation.', 'out and out', 'hard and fast', 'off and on', 'all at sea', 'c', 14),
  (24, '"Strict, rigid, and completely unalterable rules or regulations that must be followed without exception."', 'Hard and fast', 'Enough rope', 'Sweeping statement', 'Token strike', 'a', 11),
  (25, 'As soon as the security alarm went off in the jewelry store, the shoplifters ___________ and vanished into the crowded subway.', 'fell foul of', 'played havoc', 'made a clean breast', 'took to heels', 'd', 19),
  (26, '"To confess something fully, honestly, and without any reservations or attempts to hide your guilt."', 'Turn an honest living', 'Make a clean breast', 'Look down upon', 'Face the music', 'b', 20),
  (27, 'The suspect finally decided to ___________ to the police investigators, revealing exactly where the stolen funds were hidden.', 'make no bones about', 'draw on fancy', 'make a clean breast', 'turn an honest living', 'c', 20),
  (28, '"To state or admit something directly, clearly, and without showing any hesitation, doubt, or reservation."', 'Pay through nose', 'Flog a dead horse', 'Draw on fancy', 'Make no bones about', 'd', 32),
  (29, 'He didn''t want to break the rules, so he chose to ___________ by working overtime at the manufacturing plant instead of gambling.', 'turn an honest living', 'pay through nose', 'draw on fancy', 'make no bones about', 'a', 37),
  (30, '"To pay an extraordinarily high, unreasonable, or exorbitant price for a good or service."', 'Strike a bargain', 'Pay through nose', 'On the cuff', 'Cut no ice', 'b', 33),
  (31, 'Because they booked their holiday flights at the very last minute during peak season, they had to ___________.', 'pay through nose', 'cut no ice', 'strike a bargain', 'speak mind', 'a', 33),
  (32, 'The historical novelist had to ___________ to vividly reconstruct the daily conversations of the 14th-century kings.', 'stave off', 'take after', 'draw on fancy', 'fall foul of', 'c', 34),
  (33, '"To resemble or look like an older family member in physical appearance, behavioral traits, or character."', 'Stave off', 'Ill at ease', 'Take after', 'In a fix', 'c', 36),
  (34, 'The company managed to ___________ immediate bankruptcy by securing an emergency loan from a consortium of state banks.', 'stave off', 'take after', 'play havoc', 'run short', 'a', 35),
  (35, '"To temporarily delay, ward off, prevent, or keep an unpleasant situation or disaster at bay."', 'Lay by', 'Bring to book', 'Stave off', 'Give a wide berth', 'c', 35),
  (36, 'Since childhood, she has always ___________ her grandmother, sharing the exact same sharp wit, green eyes, and love for classic literature.', 'staved off', 'stood by', 'taken after', 'made a clean breast', 'c', 48),
  (37, '"To become lazy, self-satisfied, or complacent due to past achievements, stopping all further hard work."', 'Move heaven and earth', 'Rest on laurels', 'Stand by', 'Bring to book', 'b', 29),
  (38, '"A warning or clear indication that severe actions, strict punishments, firing, or structural changes are about to happen."', 'Rest on laurels', 'Heads will roll', 'Sore point', 'Cold comfort', 'b', 30),
  (39, 'After the multimillion-dollar security breach was exposed at the bank, the CEO announced that ___________ in the IT security department.', 'birds of a feather will flock', 'a hard nut will crack', 'heads will roll', 'small talk will happen', 'c', 30),
  (40, '"To make every possible human effort, utilize all options, and explore every resource to achieve a goal."', 'Flog a dead horse', 'Move heaven and earth', 'Burn one''s boats', 'Mince matters', 'b', 52),
  (41, '"To deliberately destroy or eliminate any possibility of retreating or returning to a previous situation or position."', 'Burn one''s boats', 'Rest on laurels', 'Stave off', 'Take after', 'a', 61),
  (42, '"To speak in a round-about, indirect, or sugarcoated manner to avoid hurting someone''s feelings or revealing harsh truths."', 'Mince matters', 'Beat about the bush', 'Make no bones about', 'Move heaven and earth', 'a', 60),
  (43, 'The doctor didn''t ___________; he told the family directly that the patient''s condition was extremely critical and required immediate surgery.', 'flog a dead horse', 'pay through nose', 'mince matters', 'draw on fancy', 'c', 60),
  (44, '"To talk about completely irrelevant, non-essential details in a round-about way instead of addressing the core issue directly."', 'Mince matters', 'Beat about the bush', 'Face the music', 'All at sea', 'b', 62),
  (45, '"To remain completely loyal, supportive, and dependable to someone during their most difficult times or crises."', 'Take after', 'Give a wide berth', 'Bring to book', 'Stand by', 'd', 53),
  (46, '"To punish an individual officially, or call them to account for a crime, blunder, or misdemeanor."', 'Give a wide berth', 'Rest on laurels', 'Bring to book', 'Heads will roll', 'c', 46),
  (47, '"To keep a safe, deliberate distance from a person or thing that is considered highly troublesome, volatile, or dangerous."', 'Give a wide berth', 'Stand by', 'Fell foul of', 'All at sea', 'a', 47),
  (48, '"To feel highly uncomfortable, anxious, self-conscious, or awkward in a particular social gathering or environment."', 'All at sea', 'Ill at ease', 'Under a cloud', 'In a tight corner', 'b', 41),
  (49, '"To be caught in a highly complex dilemma, predicament, or problematic situation where a solution is hard to find."', 'In a fix', 'In a tight corner', 'All at sea', 'Under a cloud', 'a', 42),
  (50, '"To suffer from an acute shortage, deficit, or insufficient supply of essential resources like money, time, or goods."', 'Lay by', 'Run short', 'Stave off', 'Play fast and loose', 'b', 44),
  (51, '"To save, store away, or put aside money and materials systematically for future usage or emergencies."', 'Lay by', 'Run short', 'Pay through nose', 'On the cuff', 'a', 45),
  (52, '"An extremely sensitive, painful, or embarrassing topic that causes immediate anger, irritation, or emotional distress when brought up."', 'A sore point', 'Cold comfort', 'Hard nut to crack', 'Sweeping statement', 'a', 64),
  (53, '"Consolation, sympathy, or encouragement that is so slight, weak, or poor that it fails to make a person feel any better."', 'A sore point', 'Hard nut to crack', 'Token strike =', 'Cold comfort', 'd', 55),
  (54, '"A highly complicated problem to solve, a challenging goal to reach, or an incredibly stubborn individual to handle."', 'Hard nut to crack', 'Wild goose chase', 'White elephant', 'Sweeping statement', 'a', 57),
  (55, '"To treat a person in a completely irresponsible, erratic, deceitful, or inconsistent manner, changing positions constantly."', 'Turn a deaf ear', 'Play fast and loose', 'Speak one''s mind', 'Strike a bargain', 'b', 63),
  (56, '"To completely ignore, disregard, or refuse to pay attention to someone''s earnest requests, appeals, or warnings."', 'Play fast and loose', 'Cut no ice', 'Turn a deaf ear', 'Be at sea', 'c', 65),
  (57, '"To fail entirely to influence, convince, impress, or change the opinion of a person or a group."', 'Turn a deaf ear', 'Play fast and loose', 'Strike a bargain', 'Cut no ice', 'd', 39),
  (58, '"To express your deep-seated thoughts, real opinions, and feelings with total honesty and blunt frankness."', 'Strike a bargain', 'Cut no ice', 'Speak one''s mind', 'Turn a deaf ear', 'c', 66),
  (59, '"To successfully conclude an agreement, compromise, or settle financial transactions on mutually favorable terms."', 'Strike a bargain', 'Speak one''s mind', 'Cut no ice', 'Play fast and loose', 'a', 38),
  (60, 'Despite facing heavy losses and supply chain issues in the first two years of starting her organic skincare brand, Priya kept investing in product quality because she knew it would pay off _________.', 'In the long run', 'In a pickle', 'Out of hand', 'By fits and starts', 'a', 68),
  (61, 'What does the idiom "To be always at one''s beck and call" mean?', 'To be independent and self-reliant', 'To be at one''s disposal / ready to serve a master', 'To get into an unexpected problem or danger', 'To avoid someone deliberately due to past conflicts', 'b', 71),
  (62, 'Ever since the new manager took over, he has been ignoring and disregarding every single cost-cutting suggestion made by the junior staff. Which idiom correctly describes the manager''s reaction?', 'Sweeping statement', 'Turned a deaf ear', 'Rose like a phoenix', 'Made a clean breast', 'b', 1),
  (63, 'The legal team was completely perplexed and confused by the sudden change in the witness''s testimony during the cross-examination. Identify the idiom that matches the underlined meaning:', 'Fair and square', 'High and dry', 'Out and out', 'At one''s wit''s end', 'd', 77),
  (64, 'The local environmental group decided to _________ against the factory''s expansion plan, organizing protests and filing legal petitions to block it completely.', 'Fight tooth and nail', 'Rest on laurels', 'Build castles in the air', 'Burn one''s boat', 'a', 78),
  (65, 'What is the meaning of the idiom "The green-eyed monster"?', 'A dangerous animal or unforeseen competitor', 'A person who likes talking without wanting to listen to others', 'Used as a way of talking about jealousy', 'A very rich person who spends money without any worry', 'c', 81),
  (66, 'The CEO called an urgent press conference to _________ regarding the company''s sudden drop in quarterly profits, ensuring no false rumors were spread.', 'Slip off', 'Run riot', 'Drop names', 'Set the record straight', 'd', 88),
  (67, 'Rohan is known as a _________ in his neighborhood because he spends his weekends volunteering at the local shelter and helping senior citizens with their groceries.', 'Good Samaritan', 'Bull in a china shop', 'Wet behind the ears', 'Fair-weather friend', 'a', 89),
  (68, 'There was _________ between the two business partners after the secret financial audit revealed that one of them had been manipulating the accounts.', 'Cold comfort', 'Bad blood', 'No bones about', 'Safe and sound', 'b', 93),
  (69, 'The marketing team decided to _________ and implement the digital campaign across all available social media channels rather than testing it in small phases.', 'Turn up one''s nose', 'Face the music', 'Go the whole hog', 'Keep under wraps', 'c', 95),
  (70, 'The tech start-up had to _________ a massive portion of its venture capital funding just to acquire the advanced AI servers needed for development.', 'Lay out', 'Turn down', 'Put up with', 'Fall flat', 'a', 97),
  (71, 'Due to the sudden economic recession and a drop in manufacturing orders, the automobile factory announced that it was _________ over fifty assembly line workers.', 'Cutting no ice', 'Laying off', 'Taking to task', 'Bringing to light', 'b', 101),
  (72, 'What does the idiom "By leaps and bounds" mean when describing a business''s growth?', 'Progressing at an incredibly rapid and quick pace', 'Declining steadily due to poor financial management', 'Moving forward erratically and with frequent interruptions', 'Operating safely under strict government regulations', 'a', 104),
  (73, 'We were planning a surprise anniversary party for our parents, but my younger brother accidentally _________ during Sunday dinner.', 'Sat on the fence', 'Spilled the beans', 'Kept under wraps', 'Struck a chill', 'b', 106),
  (74, 'The army general explicitly instructed the commando unit to _________ the rescue operation exactly as planned without making any real-time alterations.', 'Take after', 'Carry out', 'Mince matters', 'Run down', 'b', 109),
  (75, 'All his grand plans of opening a chain of luxury restaurants _________ when his primary investor pulled out of the deal at the last minute.', 'Went to the winds', 'Set the record straight', 'Made a clean breast', 'Struck a bargain', 'a', 111),
  (76, 'Before you sign the final acquisition contract for the property, make sure your legal advisor reviews all its _________.', 'Lame excuses', 'Ins and outs', 'Token strikes', 'Soft options', 'b', 113),
  (77, 'The investors grew completely _________ with the project manager''s continuous delays and lack of clear communication.', 'In high spirits', 'Fed up', 'Fair and square', 'Stand-offish', 'b', 116),
  (78, 'What does it mean when a business vendor is caught engaging in "Sharp practices"?', 'Employing highly talented and successful executives', 'Using dishonest, underhanded, or fraudulent means to make a profit', 'Implementing strict and rigid regulatory standards inside the workplace', 'Using immense creative imagination to build a unique brand identity', 'b', 6),
  (79, 'The little boy began to _________ when he saw the massive stray dog growling near the front gate of his house.', 'Wear heart on sleeve', 'Shake in shoes', 'Face the music', 'Rest on laurels', 'b', 120),
  (80, 'Because he worked on his research thesis only by _________, it took him over three years to complete a project that should have taken six months.', 'Leaps and bounds', 'Out and out', 'Fits and starts', 'High spirits', 'c', 121),
  (81, 'The car swerved abruptly to avoid the stray animal on the highway, and the passengers escaped with just a _________.', 'Close shave', 'Sore point', 'Damp squib', 'Token strike', 'a', 4),
  (82, 'What does the idiom "Take with a grain of salt" mean when listening to a politician''s promises?', 'To believe everything blindly without asking questions', 'To listen to something with considerable doubt or skepticism', 'To praise their exceptional public speaking skills', 'To record the speech accurately for official records', 'b', 123),
  (83, 'Since the restaurant had only one set menu available for the late-night travelers, it was a case of _________ for everyone.', 'Hobson’s choice', 'Fair and square', 'Open book', 'Soft option', 'a', 126),
  (84, 'Even though the rival firm was their biggest competitor, the director chose _________ by publicly praising their innovative charity drive.', 'To give the devil his due', 'To turn a deaf ear', 'To put his foot down', 'To sit in judgement', 'a', 133),
  (85, 'She is completely upfront about her financial investments and career background; her professional life is _________.', 'A wild goose chase', 'An axe to grind', 'An open book', 'Under a cloud', 'c', 127),
  (86, 'The local politician supported the construction of the new highway park not for public welfare, but because he had _________ involving his own real estate company.', 'A bone to pick', 'An axe to grind', 'A red letter day', 'A white elephant', 'b', 137),
  (87, 'Nobody in the office likes to sit with Nitin during lunch because he is always _________ about his past achievements and wealthy lifestyle.', 'Blowing his own trumpet', 'Making a clean breast', 'Putting up with', 'Reading between lines', 'a', 132),
  (88, 'Ever since she was passed over for the promotion, she has become quite _________ and avoids interacting with her colleagues.', 'Stand-offish', 'Cool as a cucumber', 'Blue-eyed', 'Hand in glove', 'a', 117),
  (89, 'During his early twenties, Julian wasted a lot of money partying and ignoring his responsibilities, but he finally settled down after _________.', 'Rising like a phoenix', 'Sowing his wild oats', 'Burning his boats', 'Dying in harness', 'b', 145),
  (90, 'The local municipality spent millions on building a massive community fountain, but the project turned out to be _________ because it broke down within a week.', 'Of no avail', 'A sore point', 'On the verge of', 'A red letter day', 'a', 149),
  (91, 'What does the idiom "A bolt from the blue" mean when describing an event?', 'An incredibly slow and planned operational transition', 'A minor problem that can be easily fixed with little effort', 'A completely unexpected, sudden, and unpleasant occurrence', 'A deliberate celebration organized to honor a top performer', 'c', 73),
  (92, 'The continuous political arguments over the past tax reforms are still _________ for the business partners, so it is best not to mention it.', 'A red letter day', 'Blue-eyed boys', 'A sore point', 'At a stone’s throw', 'c', 64),
  (93, 'The internal defense reports regarding the new missile testing program were _________ by the government until the official press conference.', 'Brought to light', 'Kept under wraps', 'Run into', 'Cut no ice', 'b', 103),
  (94, 'I thought Rohit would help me pack my apartment for the big move, but like a true _________, he stopped answering my calls the moment I asked for assistance.', 'Good Samaritan', 'Fair-weather friend', 'Blue-eyed boy', 'Man in the street', 'b', 92),
  (95, 'The clever defense lawyer carefully evaluated all the _________ before advising his high-profile client to accept the plea deal.', 'Bones to pick', 'Sharp practices', 'Pros and cons', 'Lame excuses', 'c', 152),
  (96, 'When planning the annual construction timeline, the engineering department must _________ the unpredictable heavy monsoon seasons.', 'Take into account', 'Emerge out of thin air', 'Hold a candle to', 'Drop names', 'a', 159),
  (97, 'Samir loves to impress junior interns at the law firm by _________ of senior judges he claims to have dined with over the weekend.', 'Taking into account', 'Dropping names', 'Explaining pros and cons', 'Making flesh creep', 'b', 87),
  (98, 'The corporate merger was highly anticipated by the tech market, but due to poor execution and sudden walkouts, it unfortunately _________.', 'Rose like a phoenix', 'Emege out of thin air', 'Struck a chill to the heart', 'Ended in a fiasco', 'd', 162),
  (99, 'During the heavy military retreat, when the frontline soldiers realized they were deeply outnumbered, they had to _______ to their secondary defensive boundary lines.', 'turn up one''s nose at', 'fall back', 'high and dry', 'turn one''s head', 'b', 165),
  (100, 'What is the exact contextual meaning of the idiom "Turn up one’s nose at"?', 'To accept a gift readily without checking its value', 'To confuse different parameters or facts', 'To reject or despise something with contempt', 'To stand firmly against a tough political decision', 'c', 164)
INSERT INTO public.idiom_questions (id, question, option_a, option_b, option_c, option_d, answer, idiom_id)
VALUES
  (101, 'Ever since Rohan won the top national sports championship, the sudden fame and public praise have completely _______. He behaves incredibly superior now and completely ignores his old school batchmates.', 'turned his head', 'fallen back', 'minced his matters', 'set his face against', 'a', 164),
  (102, 'When the manufacturing firm went completely bankrupt overnight, the corrupt owners took the cash reserves and fled across the border, leaving all their factory workers _______ without a single penny or any explanation.', 'falling back', 'curry favor with', 'storm in a tea cup ...', 'high and dry', 'd', 76),
  (103, 'Identify the phrase that matches this definition: "To accept something readily, or to presuppose it as certainly true without verifying it first."', 'Turn up one''s nose at', 'Take for granted', 'Mince matters', 'Storm in a tea cup', 'b', 123),
  (104, 'The spokesperson tried to _______ during the media briefing by mixing up unrelated budget statistics, ensuring the reporters would stay confused about the real financial deficit.', 'curry favor with', 'turn one''s head', 'mince matters', 'fall back', 'c', 60),
  (105, 'The junior executive is constantly bringing customized gifts for the director, laughing at all his stale jokes, and trying desperately to _______ him to secure a fast-track promotion.', 'curry favor with', 'set one''s face against', 'turn up one''s nose at', 'take for granted', 'a', 168),
  (106, 'The environmental activist committee completely _______ the corporation''s plan to clear-cut the native forest, starting an intense campaign to block the project immediately.', 'minced matters', 'set their face against', 'took for granted', 'turned their head', 'b', 164),
  (107, 'The corporate partners spent four exhausting hours screaming at each other over the exact shade of grey to use for the breakroom tiles. It was just a massive _______.', 'storm in a tea cup', 'mincing of matters', 'falling back on lines', 'turning of one''s head', 'a', 169),
  (108, 'When the project team kept asking for extension after extension without showing any real progress, the director decided to _______ and refused to grant any more time.', 'throw down a glove', 'put one''s foot down', 'read between the lines', 'fall through', 'b', 134),
  (109, 'Politicians often design their public speeches to appeal directly to _______, focusing on everyday struggles like inflation and local civic amenities rather than complex economic theories.', 'the man in the street The man in the street (phrase) – an ordinary or common man. (आम आदमी)', 'too many irons in the fire To have too many irons in the fire (phrase) – to be engaged in too many enterprises simultaneously. (एक ही समय में बहुत सारे कार्यों में व्यस्त होना)', 'letting the cat out of the bag Let the cat out of the bag (phrase) – to utter a secret carelessly or by mistake. (गलती से राज़ उजागर करना)', 'catching up with To catch up with (phrase) – to compete with or reach the same level as someone ahead. (प्रतिस्पर्धा करना/बराबरी पर आना)', 'a', 158),
  (110, 'The domestic automobile startup worked day and night, upgrading its engine technology and manufacturing speed just to _______ its global market competitors.', 'fall through', 'let the cat out of the bag', 'catch up with', 'throw down a glove', 'c', 176),
  (111, 'Despite realizing that they lacked the financial backing and resources to win the legal lawsuit against the massive conglomerate, the small law firm chose to _______ in court.', 'put one''s foot down', 'fight to the bitter end', 'let the cat out of the bag', 'catch up with', 'b', 177),
  (112, 'When the military general realized his troops were completely surrounded with zero chance of survival, he decided to _______ and ordered his men to lower their weapons.', 'throw down a glove', 'fight to the bitter end', 'read between the lines', 'put one''s foot down', 'a', 170),
  (113, 'What is the exact contextual meaning of the idiom "Read between the lines"?', 'To find errors in a printed corporate contract', 'To read a book very quickly to save valuable time', 'To understand the hidden meaning behind written or spoken words', 'To openly express your opinions without any hesitation', 'c', 164),
  (114, 'We were planning a massive surprise retirement party for our manager next week, but Sarah accidentally _______ during the morning coffee break by asking him if he liked chocolate cake.', 'put her foot down', 'caught up with', 'let the cat out of the bag', 'fought to the bitter end', 'c', 174),
  (115, 'John is currently trying to manage a full-time job, launch a tech startup, write a fantasy novel, and learn violin all at the same time. He simply has _______.', 'too many irons in the fire', 'thrown down a glove', 'read between the lines', 'fallen through', 'a', 173),
  (116, 'The real estate deal was almost finalized, but when the bank abruptly rejected the buyer''s loan application at the last minute, the entire transaction _______.', 'read between the lines', 'fell through', 'put one''s foot down', 'caught up with', 'b', 164),
  (117, 'After discovering that his eldest son had been secretly embezzling money from the family business for years, the wealthy patriarch decided to _______ and removed his name completely from the will.', 'have the last laugh', 'turn a deaf ear', 'cut him off without a shilling', 'blaze a trail', 'c', 164),
  (118, 'When the manager noticed that several confidential project files were missing right before the audit, he began to _______, suspecting an insider was leaking data to competitors.', 'run across', 'smell a rat', 'beat a retreat', 'steer clear of', 'b', 183),
  (119, 'The employees repeatedly warned the branch head about the security vulnerabilities in the software, but he _______ to their complaints until a major data breach occurred.', 'turned a deaf ear', 'blazed a trail', 'cut them off without a shilling', 'had the last laugh', 'a', 164),
  (120, 'Everyone mocked the young inventor when he quit his job to work on eco-friendly packaging, but he _______ when a multinational company bought his patent for millions.', 'ran across', 'smelled a rat', 'steered clear of', 'had the last laugh', 'd', 164),
  (121, 'August 15th, 1947, is celebrated as a _______ in Indian history, marking the end of colonial rule and the dawn of independence.', 'dark horse', 'red letter day', 'herculean task', 'helter-skelter', 'b', 185),
  (122, 'Dr. Khanna managed _______ in the field of cardiac surgery by developing a low-cost artificial valve that saved thousands of lives.', 'to run across', 'to blaze a trail', 'to get his own back', 'to beat a retreat', 'b', 181),
  (123, 'As soon as the stray dogs saw the aggressive leopard enter the village outskirts, they stopped barking and _______ into the nearby forest.', 'steered clear of', 'got their own back', 'beat a retreat', 'put up with', 'c', 184),
  (124, 'If you want to maintain a peaceful environment at the workplace, it is always wise to _______ office politics and malicious gossip.', 'run across', 'steer clear of', 'make ducks and drakes of', 'be done for', 'b', 74),
  (125, 'After being unfairly demoted by his corrupt supervisor, Kevin vowed to _______ by exposing the supervisor''s fraudulent expenses to upper management.', 'put up with', 'get his own back', 'get the sack', 'walk at a snail''s pace', 'b', 164),
  (126, 'While clearing out my grandmother’s old wooden chest in the attic yesterday, I happened to _______ some rare letters written during World War II.', 'run across', 'make a clean breast', 'end in smoke', 'run down', 'a', 182),
  (127, 'No one expected the quiet, unrated candidate from the small town to win the national chess championship, but he proved to be a true _______.', 'dark horse', 'white elephant', 'herculean task', 'token strike', 'a', 81),
  (128, 'The retail workers found it incredibly difficult to _______ the continuous stream of rude demands from aggressive customers during the holiday rush.', 'take to one''s heels', 'put up with', 'blow one''s own trumpet', 'end in smoke', 'b', 99),
  (129, 'The accountant _______ after upper management discovered that he had been systematically inflating travel invoices for personal gain.', 'got the sack', 'blazed a trail', 'kept his head', 'ran across', 'a', 196),
  (130, 'Rescuing the stranded mountain climbers from the freezing blizzard at an altitude of 20,000 feet proved to be a _______ for the elite military team.', 'dark horse', 'herculean task', 'red letter day', 'pot luck dinner', 'b', 186),
  (131, 'The production target increased by leaps and bounds last quarter, which was a phenomenal achievement for our factory division. What does "by leaps and bounds" mean?', 'Through illegal or corrupt means', 'Very slowly and cautiously', 'At a highly rapid pace', 'With immense hesitation', 'c', 164),
  (132, 'When the false fire alarm suddenly went off inside the crowded auditorium, the panicked spectators rushed _______ toward the narrow exit doors.', 'helter-skelter', 'on the level', 'by leaps and bounds', 'down the drain', 'a', 187),
  (133, 'The elaborate plans for the grand outdoor music festival _______ when the regional administration denied the organizers a noise permit.', 'made a clean breast', 'went to the winds', 'kept under wraps', 'hit below the belt', 'b', 111),
  (134, 'Instead of reinvesting his inherited wealth into stable mutual funds, the young heir decided to _______ his fortune on luxury sports cars and extravagant overseas vacations.', 'take to his heels', 'take someone to task', 'make ducks and drakes of', 'read between the lines', 'c', 189),
  (135, 'You can trust this real estate broker blindly with your savings; he is known in the market for being entirely _______ in all his property dealings.', 'helter-skelter', 'on the level', 'done for', 'at sea', 'b', 199),
  (136, 'After their main distribution factory was completely incinerated in the accidental electrical fire, the local retail company was financially _______.', 'on the level', 'done for', 'all at sea', 'helter-skelter', 'b', 190),
  (137, 'Unable to handle the intense guilt of hiding the truth from his family any longer, the thief decided to _______ and detailed the entire burglary plot to the police officer.', 'end in smoke', 'make a clean breast', 'take to his heels', 'run someone down', 'b', 20),
  (138, 'The ambitious multi-million dollar software project, which took three years of coding and heavy investment, unfortunately _______ because the technology became entirely obsolete before launch.', 'made a clean breast', 'ended in smoke', 'had something up its sleeve', 'turned a deaf ear', 'b', 164),
  (139, 'The defense attorney did not seem worried at all about the prosecutor''s strong opening statement because she _______ that could immediately discredit the main witness.', 'had something up her sleeve', 'took to her heels', 'ended in smoke', 'turned a deaf ear', 'a', 164),
  (140, 'As soon as the fraudulent bank executives caught sight of the federal raid vehicles pulling up outside the corporate headquarters, they _______ through the back exit.', 'turned a deaf ear', 'took to their heels', 'had something up their sleeve', 'ran down the competitor', 'b', 164),
  (141, 'The stubby corporate director stubbornly _______ to the complaints regarding workplace discrimination, which ultimately led to a massive class-action lawsuit.', 'took to his heels', 'had something up his sleeve', 'turned a deaf ear', 'ran down his team', 'c', 164),
  (142, 'Because the administrative staff worked _______, typing out the official data registries manually, the approval process for the land licenses took several months.', 'at a snail''s pace', 'helter-skelter', 'on the level', 'face the music', 'a', 164),
  (143, 'It is highly unprofessional and toxic for a team leader to constantly _______ in front of external clients just to hide his own administrative failures.', 'take someone to task', 'run someone down', 'blow his own trumpet', 'face the music', 'b', 164),
  (144, 'Instead of showing genuine humility and discussing team efforts, the narcissistic CEO chose to _______ during the entire media interview, taking credit for all innovations.', 'run someone down', 'blow his own trumpet', 'face the music', 'take someone to task', 'b', 164),
  (145, 'After failing to meet the critical project deadline due to gross negligence, the operations manager had to _______ in front of the board of directors.', 'blow his own trumpet', 'run someone down', 'face the music', 'walk at a snail''s pace', 'c', 206),
  (146, 'The senior regional supervisor decided to _______ the junior officer for submitting an unverified financial expense report filled with computational errors.', 'face the music', 'take someone to task', 'blow his own trumpet', 'run someone down', 'b', 202),
  (147, 'When the exam supervisor unexpectedly informed the students that the remaining duration of the test was only two minutes, Kevin found himself completely _______.', 'on the level', 'done for', 'at his wit''s end', 'making ducks and drakes', 'c', 164),
  (148, 'If a company''s entire future depends heavily on the success of a single new product launch, the company''s reputation and capital are considered to be in deep danger. Which idiom best describes this situation?', 'Under a cloud', 'At stake', 'In a pickle', 'Done for', 'b', 207),
  (149, 'The politician didn''t focus on policy details; instead, he spoke with highly exaggerated dramatic flair just to win the loud applause and approval of the ordinary crowd. What was he doing?', 'Playing to the gallery', 'Blowing his own trumpet', 'Dropping names', 'Barking up the wrong tree', 'a', 208),
  (150, 'When asked to choose between supporting the marketing team or the design team, Rahul remained completely neutral, hesitating to take a definitive side. Rahul was:', 'Standing on his own feet', 'Biting the dust', 'Sailing in the same boat', 'Sitting on the fence', 'd', 106),
  (151, 'Ever since their bitter property dispute last year, there is absolutely no friendship left between the two brothers, and they avoid speaking to each other. Which idiom fits best?', 'Bad blood', 'No love lost between', 'Cross swords', 'Cheek by jowl', 'b', 10),
  (152, 'What is the meaning of the idiom "A man in the street"?', 'An ordinary person / Common man (आम आदमी)', 'A homeless individual (बेघर व्यक्ति)', 'A talented investigator (प्रतिभाशाली अन्वेषक)', 'A careless pedestrian (लापरवाह राहगीर)', 'a', 216),
  (153, 'The sudden horror movie jumpscare made me jump out of my seat, and I became intensely terrified. Which idiom describes my reaction?', 'Mind blew over', 'Blood running cold', 'Shaking in shoes', 'Foam at the mouth', 'b', 219),
  (154, 'The local politician was criticized for "playing to the gallery" during his budget speech. What does this mean?', 'Constructing a new art gallery for the town', 'Befooling the common man with exaggerated actions for popularity', 'Investing money wisely in public welfare infrastructure', 'Arguing aggressively with the opposition members', 'b', 221),
  (155, 'She used to be highly introverted and quiet, but recently she has finally started to converse freely and express her personality confidently. She has:', 'Dropped like flies', 'Come out of her shell', 'Stolen the show', 'Kept her head', 'b', 224),
  (156, 'The defense lawyer''s argument was completely weak because he had no evidence or facts to support his claims. The judge remarked that the lawyer did not have:', 'An axe to grind', 'A leg to stand on', 'A close shave', 'His heart on his sleeve', 'b', 227),
  (157, 'After realizing that they were completely surrounded and outnumbered by the enemy forces, the rebel troops decided to drop their weapons and surrender. Which idiom fits this?', 'Turn to heels', 'Lay down arms', 'Fight tooth and nail', 'Burn their boats', 'b', 228),
  (158, 'When the market boomed unexpectedly, the clever investor quickly bought and sold shares, maximizing his profits while the conditions remained perfect. What was he doing?', 'Feathering his nest', 'Striking a bargain', 'Making hay while the sun shines', 'Making ducks and drakes of money', 'c', 231),
  (159, 'Instead of pointing out others'' flaws, you should stop bragging, as you are always boasting about your own skills. Choose the idiom that matches "to praise oneself".', 'To blow one''s own trumpet', 'To talk through one''s hat', 'To ride the high horse', 'To drop names', 'a', 233),
  (160, 'Please be calm and patient with the new interns while they learn how to navigate this complex software over the first week.', 'Put up with', 'Bear with', 'Stand by', 'Cope with', 'b', 236),
  (161, 'The workers gathered outside the factory gates to openly express and unleash their bottled-up anger regarding the sudden deduction in their bonuses. They wanted to:', 'Give vent to', 'Run riot', 'Mince matters', 'Kick up a row', 'a', 238),
  (162, 'What is the exact meaning of the idiom "Turn a deaf ear"?', 'To become physically hard of hearing', 'Pay no attention / Disregard / Ignore', 'Listening with considerable doubt', 'To be completely puzzled', 'b', 65),
  (163, 'The ongoing boundary line dispute between the two neighboring nations has become a permanent issue of conflict for decades. The boundary line is a:', 'Sore point', 'Bone of contention', 'Hard nut to crack', 'Storm in a tea cup', 'b', 241),
  (164, 'Ever since he graduated from college, Sam refused to ask his parents for money because he wanted to be independent and support himself. Sam decided to:', 'Cut his coat according to his cloth', 'Turn an honest living', 'Stand on his own feet', 'Rest on his laurels', 'c', 71),
  (165, 'The health inspector visits the restaurant only "by fits and starts", which allows the kitchen staff to get away with bad hygiene on most days. What does the bold phrase mean?', 'Regularly', 'Suddenly', 'Irregularly', 'Rapidly', 'c', 13),
  (166, 'Select the option that correctly defines the idiom "Over head and ears".', 'To be completely or totally immersed in something', 'To listen to rumors carefully', 'Standing in a very dangerous situation', 'Being deep in an argument with your boss', 'a', 244),
  (167, 'The manager decided to stop working and wrap up the meeting because it was getting late in the evening. He said, "Let''s ________."', 'face the music', 'call it a day', 'clear out of the way', 'blow over', 'b', 247),
  (168, 'No matter how stressful my work environment gets, I have no choice but to tolerate it until I find a better job opportunity.', 'To put up with', 'To turn down', 'To look down upon', 'To carry out', 'a', 248),
  (169, 'The mischievous boy had to "face the music" when his father discovered that he had broken the neighbor''s window glass. What does the idiom mean?', 'Listen to beautiful melodies', 'To escape without any punishment', 'To bear the unpleasant consequences or criticism', 'To apologize humbly for a mistake', 'c', 206),
  (170, 'The voluntary doctors provided "yeoman''s service" to the earthquake-hit villages, setting up free medical camps overnight. What kind of service is this?', 'Extremely cheap labor', 'Excellent, valuable social work', 'Unreliable or irregular assistance', 'Selfish work done for profit', 'b', 251),
  (171, 'When Simran''s dog passed away after being sick for weeks, she was deeply affected by the loss and couldn''t stop crying for days. She took the loss:', 'To heart', 'With a grain of salt', 'Under wraps', 'To her heels', 'a', 252),
  (172, 'The detective instantly "smelled a rat" when the suspect gave an alibi that contradicted his phone records. What does this mean?', 'He found a dead animal under the table', 'He became highly suspicious of a trick or deception', 'He decided to close the investigation file', 'He made a clean breast of everything', 'b', 183),
  (173, 'The space agency decided to "move heaven and earth" to ensure the stranded astronauts were brought back safely. What does this indicate?', 'They spent money carelessly on luxury items', 'They postponed the rescue project indefinitely', 'They tried every possible effort and route', 'They blamed other nations for the crisis', 'c', 256),
  (174, 'The tourist realized too late that the street vendor had "taken him for a ride" by selling him a fake gemstone at triple the original price. The vendor had:', 'Given him a free lift in a car', 'Promoted his business honestly', 'Deceived or cheated him', 'Guided him around the city monuments', 'c', 259),
  (175, 'The ruthless gang executed their plan and murdered the witness deliberately, without any mercy or emotion. Which idiom best describes this act?', 'In cold blood', 'A damp squib', 'To bite the dust', 'Cold comfort', 'a', 23),
  (176, 'Everyone expected the new software launch to revolutionize the industry, but it turned out to be a complete disappointment.', 'To die in harness', 'A damp squib', 'Wear and tear', 'Soft option', 'b', 122),
  (177, 'The defending champion fought hard but ultimately had to accept defeat in the final round of the tournament.', 'To strain every nerve', 'To speak one''s mind', 'To bite the dust', 'Hand in glove', 'c', 262),
  (178, 'When the police raided the illegal gambling den, the suspects panicked and ran away in fear.', 'To fall back on', 'To take to one''s heels', 'To lose ground', 'To face the music', 'b', 195),
  (179, 'After losing his passport and wallet in a completely foreign city, Rohan felt completely lost and confused.', 'All at sea', 'In high spirits', 'Fair and square', 'Out and out', 'a', 5),
  (180, 'Telling a broke student that they saved two rupees on a luxury meal is a form of slight satisfaction that doesn''t actually help them.', 'Gift of the gab', 'Maiden speech', 'Cold comfort', 'A wild goose chase', 'c', 55),
  (181, 'The sudden announcement of the company’s bankruptcy was an unexpected and highly unpleasant shock to all its employees.', 'A bolt from the blue', 'A white elephant', 'A hard nut to crack', 'A damp squib', 'a', 73),
  (182, 'The corrupt politician used his official position to illegally accumulate massive wealth and enrich himself.', 'To flog a dead horse', 'To feather one''s nest', 'To cope with', 'To speak one''s mind', 'b', 272),
  (183, 'The dedicated police officer refused to retire and chose to work until the day he passed away while on duty.', 'To take to one''s heels', 'To add fuel to the fire', 'To die in harness', 'To make a clean breast', 'c', 263),
  (184, 'The escaped convict managed to run away and elude the police by running swiftly through the narrow alleys.', 'To meet by chance', 'To show a clean pair of heels', 'To make a mountain of a molehill', 'To curry favor', 'b', 277),
  (185, 'Trying to convince the company to restart production of its obsolete, decades-old pager devices is just a complete waste of effort.', 'To flog a dead horse', 'To strain every nerve', 'To fall back on', 'To be all at sea', 'a', 271),
  (186, 'The medical team worked tirelessly and made the utmost possible efforts to save the critically injured patient.', 'To lose ground', 'To speak one''s mind', 'To get one''s own back', 'To strain every nerve', 'd', 265),
  (187, 'Since both families were hit by the same devastating flash floods, they found themselves sharing the exact same difficult situation.', 'In a tight corner', 'Sailing in the same boat', 'Under a cloud', 'Fair and square', 'b', 213),
  (188, 'The defense lawyer possessed a remarkable ability to speak eloquently, easily swaying the entire jury with his words.', 'Gift of the gab', 'Maiden speech', 'Soft option', 'A little gush of gratitude', 'a', 125),
  (189, 'The poor laborer worked multiple shifts just to earn enough money to escape starvation and feed his family.', 'To keep the wolf from the door', 'To make one''s blood boil', 'To add fuel to the fire', 'To turn a deaf ear', 'a', 282),
  (190, 'Instead of taking the challenging and risky advanced course, Sam decided to take the easy and agreeable path.', 'Hard and fast', 'Soft option', 'In cold blood', 'Out and out', 'b', 114),
  (191, 'Upon receiving the surprise scholarship reward, the young student experienced an overwhelming feeling of thankfulness toward her mentors.', 'A little gush of gratitude', 'Maiden speech', 'Cold comfort', 'Gift of the gab', 'a', 281),
  (192, 'With the emergence of modern streaming apps, traditional cable television channels have started to lose their popularity significantly.', 'To bite the dust', 'To lose ground', 'To fall back on', 'To show a clean pair of heels', 'b', 268),
  (193, 'When his business partnership abruptly collapsed, Mike had to rely on his personal savings as his ultimate backup option.', 'To die in harness', 'To strain every nerve', 'To fall back on', 'To flog a dead horse', 'c', 267),
  (194, 'The rude behavior of the store clerk made the customer completely furious and angry.', 'To make one''s blood boil', 'To speak one''s mind', 'To keep the wolf from the door', 'To be all at sea', 'a', 283),
  (195, 'The heavy machinery in the industrial plant suffered a massive amount of physical damage due to continuous daily usage over the past decade.', 'Soft option', 'Wear and tear', 'A damp squib', 'In cold blood', 'b', 264),
  (196, 'By bringing up old, forgotten arguments during the peaceful meeting, Jack succeeded only in causing additional anger and worsening the matter.', 'To fall back on', 'To keep the wolf from the door', 'To add fuel to the fire', 'To lose ground', 'c', 274),
  (197, 'The two corporate executives were operating in a highly secretive and exceptionally close relationship to manipulate the market prices.', 'Hand in glove', 'At the eleventh hour', 'Cross swords', 'Out and out', 'a', 144),
  (198, 'Instead of handling the minor billing mistake calmly, the customer began to exaggerate it wildly and give great importance to a little thing.', 'To speak one''s mind', 'To make a mountain of a molehill', 'To make one''s blood boil', 'To strain every nerve', 'b', 278),
  (199, 'The manager decided to be completely frank and honest during the interview, expressing his true opinions directly to the board.', 'To add fuel to the fire', 'To take to one''s heels', 'To speak one''s mind', 'To die in harness', 'c', 266),
  (200, 'The newly elected prime minister delivered an exceptional first speech that captivated the entire parliament.', 'Maiden speech', 'Gift of the gab', 'Soft option', 'Cold comfort', 'a', 269)
INSERT INTO public.idiom_questions (id, question, option_a, option_b, option_c, option_d, answer, idiom_id)
VALUES
  (201, 'The continuous changes to the project requirements were submitted at the very last moment, causing massive panic among the developers.', 'At the eleventh hour', 'Wear and tear', 'Sailing in the same boat', 'Hand in glove', 'a', 284),
  (202, 'Despite facing severe personal hardships and massive financial constraints, Maya managed to face and deal with her difficulties successfully.', 'To lose ground', 'To cope with', 'To make a mountain of a molehill', 'To speak one''s mind', 'b', 273),
  (203, 'Learning coding fundamentals early in college will eventually be highly beneficial and helpful in securing a high-paying tech job later in your career.', 'Out of the question', 'Go a long way towards doing something', 'Take exception', 'Measure up', 'b', 286),
  (204, 'The smooth-talking salesman possessed an extraordinary talent for speaking, effortlessly convincing the hesitant couple to buy the expensive car.', 'Gift of the gab', 'Man of letters', 'Cool as a cucumber', 'High handed', 'a', 125),
  (205, 'When the main electricity grid failed abruptly during the storm, all operations at the massive factory came to a complete halt.', 'Standstill', 'Run down', 'On the brink of', 'Go down the drain', 'a', 291),
  (206, 'The two rival politicians strongly disagreed with each other''s policies and began to argue fiercely during the live televised debate.', 'Pore over', 'Wears heart on sleeves', 'Cross swords', 'Measure up', 'c', 214),
  (207, 'The research scholar spent hours in the library to carefully examine and go through the ancient historical manuscripts.', 'Put across', 'Run down', 'Turn down', 'Pore over', 'd', 246),
  (208, 'With the prices of groceries skyrocketing, the low-wage worker found it incredibly difficult to manage his expenses and balance his income with expenditure.', 'Make both ends meet', 'Grease anybody’s palm', 'Leave in the lurch', 'Caught red handed', 'a', 295),
  (209, 'Instead of motivating the young athletes, the bitter coach chose to publicly criticize their performance, damaging their self-confidence.', 'Face the music', 'Run down', 'Gift of the gab', 'Go a long way towards doing something', 'b', 110),
  (210, 'The shady contractor attempted to offer a large sum of illegal money to the government inspector to secure a quick approval for his building project.', 'Go down the drain', 'A close shave', 'Grease anybody’s palm', 'In high spirits', 'c', 296),
  (211, 'The unfaithful business partner chose to completely abandon and desert his associate in a highly critical financial crisis.', 'Leave in the lurch', 'Scapegoat', 'A red letter day', 'Turn down', 'a', 297),
  (212, 'The notorious shoplifter was caught red-handed by the security guards just as he was stuffing the stolen diamond necklace into his jacket.', 'On the brink of', 'Caught red handed', 'Standstill', 'Cross swords', 'b', 298),
  (213, 'Scientists warn that several endangered species are now standing directly on the point of extinction due to massive global deforestation.', 'On the brink of', 'Go down the drain', 'Measure up', 'On good terms', 'a', 292),
  (214, 'After failing the audit miserably, the corrupt corporate director had to face the unpleasant consequences and bear the heavy legal criticism.', 'Cross swords', 'Gift of the gab', 'Doctor the accounts', 'Face the music', 'd', 15),
  (215, 'The defense attorney used her exceptional ability to speak impressively to sway the opinion of the jury in favor of her innocent client.', 'Man of letters', 'Gift of the gab', 'Wears heart on sleeves', 'Stole the show', 'b', 125),
  (216, 'When the multi-million dollar tech startup went bankrupt within six months, all the investor money was lost forever.', 'Went down the drain', 'Made both ends meet', 'Ran down', 'Stood at a standstill', 'a', 303),
  (217, 'The speeding motorcycle swerved sharply at the last microsecond, managing a narrow escape from a fatal collision with a heavy truck.', 'A dark horse', 'A close shave', 'Cool as a cucumber', 'In high spirits', 'b', 299),
  (218, 'Even when the entire fire station alarm went off accidentally, the senior captain remained completely calm and not nervous at all.', 'High handed', 'On the brink of', 'Caught red handed', 'Cool as a cucumber', 'd', 142),
  (219, 'Winning the championship trophy put the entire team in a highly cheerful and enthusiastic frame of mind.', 'In high spirits', 'Scapegoat', 'Man of letters', 'Measure up', 'a', 115),
  (220, 'The innocent junior accountant was unfairly blamed for the massive funds embezzled by the top management executives.', 'Turn down', 'Scapegoat', 'Dark horse', 'On good terms', 'b', 258),
  (221, 'The day Rahul received his official appointment letter for the prestigious civil services was a truly memorable and joyful day of his life.', 'A red letter day', 'Standstill', 'Gift of the gab', 'A close shave', 'a', 139),
  (222, 'You can always know exactly how Tina feels about a situation because she expresses her feelings openly instead of hiding them.', 'Doctors the accounts', 'Wears her heart on her sleeves', 'Crosses swords', 'Runs down', 'b', 308),
  (223, 'The old friends decided to meet over coffee to settle their old disputes, forgive past mistakes, and pay off old scores.', 'To pay off old scores', 'To measure up', 'To turn down', 'To leave in the lurch', 'a', 311),
  (224, 'Professor Sharma, an eminent scholar who spent his entire life studying ancient classics, is widely recognized as a highly accomplished intellectual.', 'Scapegoat', 'Dark horse', 'Man of letters', 'Gift of the gab', 'c', 289),
  (225, 'The committee decided to reject the initial proposal because it lacked a detailed budget framework and feasibility study.', 'Turn down', 'Pull up', 'Lose head', 'Pull strings', 'a', 98),
  (226, 'Even after working together for years, the two business rivals managed to agree with each other on the new expansion policy.', 'At sixes and sevens', 'On good terms', 'Dark horse', 'Bad blood', 'b', 300),
  (227, 'The lead actor gave a brilliant performance that won everyone''s praise and completely captivated the audience last night.', 'Mince matters', 'Stole the show', 'Cut no ice', 'Close the book', 'b', 302),
  (228, 'Although the new recruit tried his best, his performance failed to reach the required level expected by the senior managers.', 'Turn down', 'Turn one''s head', 'Measure up', 'Pull up', 'c', 288),
